urlset:
{% for page in static_pages %}

  {{ page.loc }}
  {{ page.changefreq }}
  {{ page.priority }}

{% endfor %}
{% for article in articles %}

  {{ base_url }}/blog/{{ article.slug }}
  {{ (article.updated_at or article.published_at).strftime('%Y-%m-%d') if (article.updated_at or article.published_at) else '' }}
  monthly
  0.7

{% endfor %}
{% for project in projects %}

  {{ base_url }}/projets
  weekly
  0.6

{% endfor %}
